import React from 'react';
import HolidayManagement from '../HolidayManagement';
import OptimizedIcon from '../ui/OptimizedIcon';

/**
 * HolidayManager - Self-contained holiday management component
 * Handles adding, deleting, and viewing holidays
 */
const HolidayManager = ({ 
  holidays, 
  onAddHoliday, 
  onDeleteHoliday, 
  API_BASE_URL, 
  token, 
  isLoading 
}) => {
  return (
    <div className="bg-white rounded-2xl shadow-lg p-6">
      <div className="flex items-center mb-6">
        <div className="w-8 h-8 bg-orange-100 rounded-lg flex items-center justify-center mr-3">
          <OptimizedIcon name="party" size={20} color="#ea580c" />
        </div>
        <div>
          <h2 className="text-xl font-bold text-gray-900">Holiday Management</h2>
          <p className="text-sm text-gray-600">Manage official holidays and observances</p>
        </div>
      </div>

      <HolidayManagement
        holidays={holidays}
        API_BASE_URL={API_BASE_URL}
        token={token}
        onAddHoliday={onAddHoliday}
        onDeleteHoliday={onDeleteHoliday}
        isLoading={isLoading}
      />
    </div>
  );
};

export default HolidayManager;
